def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def lucas_lehmer(p):
    if not is_prime(p):
        return False

    if p == 2:
        return True

    M_p = (1 << p) - 1

    s = 4
    for _ in range(p - 2):
        s = (s * s - 2) % M_p

    return s == 0
